INSERT INTO bluenote_comment.content_comment (
    comment_id, note_id, note_author_id, user_id, root_id, parent_comment_id,
    reply_to_user_id, level, comment_status, like_count_snapshot,
    reply_count_snapshot, hot_score_snapshot, created_at, updated_at
) VALUES (
    #{commentId}, #{noteId}, #{noteAuthorId}, #{userId}, #{rootId}, #{parentCommentId},
    #{replyToUserId}, #{level}, #{commentStatus}, #{likeCountSnapshot},
    #{replyCountSnapshot}, #{hotScoreSnapshot}, #{createdAt}, #{updatedAt}
