mapper.select:
SELECT 
FROM bluenote_comment.content_comment
WHERE note_id = #{noteId}
  AND level = 1
  AND comment_status = 'VISIBLE'



      AND (
        hot_score_snapshot < #{cursorHotScore}
        OR (
          hot_score_snapshot = #{cursorHotScore}
          AND created_at < #{cursorCreatedAt}
        )
        OR (
          hot_score_snapshot = #{cursorHotScore}
          AND created_at = #{cursorCreatedAt}
          AND comment_id < #{cursorCommentId}
        )
      )


      AND (
        created_at > #{cursorCreatedAt}
        OR (created_at = #{cursorCreatedAt} AND comment_id > #{cursorCommentId})
      )


      AND (
        created_at < #{cursorCreatedAt}
        OR (created_at = #{cursorCreatedAt} AND comment_id < #{cursorCommentId})
      )





    ORDER BY hot_score_snapshot DESC,
             created_at DESC,
             comment_id DESC


    ORDER BY created_at ASC, comment_id ASC


    ORDER BY created_at DESC, comment_id DESC


LIMIT #{size}

SELECT 
FROM bluenote_comment.content_comment
WHERE root_id = #{rootId}
  AND level = 2
  AND comment_status = 'VISIBLE'

  AND (
    created_at > #{cursorCreatedAt}
    OR (created_at = #{cursorCreatedAt} AND comment_id > #{cursorCommentId})
  )

ORDER BY created_at ASC, comment_id ASC
LIMIT #{size}

mapper.update:
UPDATE bluenote_comment.content_comment
SET comment_status = 'DELETED',
    updated_at = #{updatedAt}
WHERE comment_id = #{commentId}
  AND comment_status = 'VISIBLE'

UPDATE bluenote_comment.content_comment
SET comment_status = 'DELETED',
    updated_at = #{updatedAt}
WHERE root_id = #{rootId}
  AND comment_status = 'VISIBLE'

UPDATE bluenote_comment.content_comment
SET reply_count_snapshot = GREATEST(reply_count_snapshot + #{delta}, 0),
    hot_score_snapshot = GREATEST(hot_score_snapshot + #{hotDelta}, 0),
    updated_at = #{updatedAt}
WHERE comment_id = #{rootId}

UPDATE bluenote_comment.content_comment
SET like_count_snapshot = GREATEST(like_count_snapshot + #{delta}, 0),
    hot_score_snapshot = GREATEST(hot_score_snapshot + #{hotDelta}, 0),
    updated_at = #{updatedAt}
WHERE comment_id = #{commentId}
